async (params, browser) => {
  // Open Google Calendar
  await browser.open('https://calendar.google.com/calendar/r')

  // Wait for calendar to load
  await browser.waitForSelector('[role=\'main\'], [data-eventid], .FAxxKc', 20000)

  // Let calendar and sidebar fully render
  await browser.wait(3000)

  // Scrape sidebar calendar list
  const calendars_result = await browser.evaluate(`const calendars = []; const sidebarItems = document.querySelectorAll('[class*="calendar-list"] li, .side-panel li, [data-calendarid], [role="listitem"], li[data-calendarid]'); if (sidebarItems.length > 0) { sidebarItems.forEach(item => { const label = item.getAttribute('aria-label') || item.getAttribute('data-calendarid') || ''; const nameEl = item.querySelector('span, label, .calendar-label'); const name = nameEl ? nameEl.textContent.trim() : label || item.textContent.trim(); if (!name || name.length > 100) return; const checkbox = item.querySelector('input[type="checkbox"], [role="checkbox"]'); const isVisible = checkbox ? (checkbox.checked || checkbox.getAttribute('aria-checked') === 'true') : true; const colorEl = item.querySelector('[style*="background"], .calendar-color-bullet, svg circle, [class*="color"]'); let color = ''; if (colorEl) { const style = window.getComputedStyle(colorEl); color = style.backgroundColor || colorEl.getAttribute('fill') || ''; } const calId = item.getAttribute('data-calendarid') || ''; calendars.push({ name: name.substring(0, 100), calendar_id: calId, visible: isVisible, color: color }); }); } if (calendars.length === 0) { const allLabels = document.querySelectorAll('[aria-label*="calendar" i], [data-calendarid]'); allLabels.forEach(el => { const name = el.getAttribute('aria-label') || el.getAttribute('data-calendarid') || el.textContent.trim(); if (!name) return; const calId = el.getAttribute('data-calendarid') || ''; const style = window.getComputedStyle(el); calendars.push({ name: name.substring(0, 100), calendar_id: calId, visible: true, color: style.backgroundColor || '' }); }); } const uniqueCalendars = []; const seenNames = new Set(); calendars.forEach(c => { const key = c.name.toLowerCase(); if (!seenNames.has(key)) { seenNames.add(key); uniqueCalendars.push(c); } }); return { calendar_count: uniqueCalendars.length, calendars: uniqueCalendars }`)

  return calendars_result
}
